import{_ as e,o as l,c as i,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"用户控制、撤销、容错、错误预防与恢复","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/01-principles/04-control-undo-tolerance-error-prevention-recovery.md","filePath":"03-interaction-design/notes/01-principles/04-control-undo-tolerance-error-prevention-recovery.md","lastUpdated":1784542968000}'),s={name:"03-interaction-design/notes/01-principles/04-control-undo-tolerance-error-prevention-recovery.md"};function t(r,a,o,d,h,p){return l(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="用户控制、撤销、容错、错误预防与恢复" tabindex="-1">用户控制、撤销、容错、错误预防与恢复 <a class="header-anchor" href="#用户控制、撤销、容错、错误预防与恢复" aria-label="Permalink to &quot;用户控制、撤销、容错、错误预防与恢复&quot;">​</a></h1><p>用户控制是用户能主动开始、停止、检查和退出操作；撤销恢复最近操作前的有效状态；容错让系统在合理输入偏差或局部故障下仍可完成任务；错误预防减少错误发生；错误恢复帮助用户识别影响、保留有效工作并回到可继续状态。</p><h2 id="概念边界" tabindex="-1">概念边界 <a class="header-anchor" href="#概念边界" aria-label="Permalink to &quot;概念边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>发生时机</th><th>核心机制</th><th>例子</th></tr></thead><tbody><tr><td>用户控制</td><td>操作前、进行中和完成后</td><td>明确触发、取消、暂停、确认与退出</td><td>用户主动提交，不在聚焦字段时自动跳转</td></tr><tr><td>撤销</td><td>操作已生效后</td><td>记录反向操作或恢复先前版本</td><td>恢复刚删除的列表项</td></tr><tr><td>容错</td><td>输入或环境偏离理想条件时</td><td>接受等价输入、保留局部成功、幂等与重试</td><td>电话号允许常见空格并规范化</td></tr><tr><td>错误预防</td><td>错误发生前</td><td>约束、校验、复核、默认值与风险提示</td><td>汇款前复核收款人和金额</td></tr><tr><td>错误恢复</td><td>错误发生后</td><td>描述、定位、保留、修正、重试或回滚</td><td>提交失败后保留字段并定位错误</td></tr></tbody></table><p>撤销不是取消：取消停止尚未完成的操作，撤销反转已经完成的操作。重试也不是撤销：重试再次尝试同一意图，必须明确是否会产生重复副作用。</p><h2 id="错误处理链" tabindex="-1">错误处理链 <a class="header-anchor" href="#错误处理链" aria-label="Permalink to &quot;错误处理链&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;用户意图&quot;] --&gt; P[&quot;预防：约束与复核&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; O[&quot;执行操作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; C{&quot;结果是否满足不变量？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|是| S[&quot;成功反馈&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|否| D[&quot;识别错误与影响范围&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; K[&quot;保留有效输入与工作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; R[&quot;修正、重试、回滚或求助&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; U[&quot;必要时撤销&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U --&gt; A</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; P</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>确定性业务不变量必须由服务端、数据库或受控系统保证。界面约束和提示可以减少错误，不能代替授权、金额校验、唯一性和事务一致性。</p><h2 id="用户控制" tabindex="-1">用户控制 <a class="header-anchor" href="#用户控制" aria-label="Permalink to &quot;用户控制&quot;">​</a></h2><h3 id="操作前" tabindex="-1">操作前 <a class="header-anchor" href="#操作前" aria-label="Permalink to &quot;操作前&quot;">​</a></h3><ul><li>明确操作对象、范围、结果与风险。</li><li>用户选择选项时不应意外提交、导航或打开新上下文。</li><li>默认值可以提高效率，但高风险默认必须可见且合理。</li><li>自动保存应说明保存范围、状态和冲突处理。</li></ul><h3 id="操作中" tabindex="-1">操作中 <a class="header-anchor" href="#操作中" aria-label="Permalink to &quot;操作中&quot;">​</a></h3><ul><li>长任务说明进度、阶段和是否可以取消。</li><li>取消要定义是停止客户端等待，还是请求服务端终止任务。</li><li>若任务不能安全中止，应说明“可以离开，处理会继续”，而不是提供无效取消。</li><li>键盘焦点保持在可理解位置，动态内容不随意夺取焦点。</li></ul><h3 id="操作后" tabindex="-1">操作后 <a class="header-anchor" href="#操作后" aria-label="Permalink to &quot;操作后&quot;">​</a></h3><ul><li>显示权威结果、对象标识和下一步。</li><li>支持撤销、恢复、版本历史或人工处理中的至少一种合理路径。</li><li>用户可以重新进入并检查结果，不依赖短暂提示。</li></ul><h2 id="撤销机制" tabindex="-1">撤销机制 <a class="header-anchor" href="#撤销机制" aria-label="Permalink to &quot;撤销机制&quot;">​</a></h2><h3 id="反向操作" tabindex="-1">反向操作 <a class="header-anchor" href="#反向操作" aria-label="Permalink to &quot;反向操作&quot;">​</a></h3><p>保存一次操作所需的反向命令。例如将任务状态从 A 改为 B，撤销操作尝试从 B 恢复 A。若对象随后被他人修改，简单反向命令可能覆盖新数据，必须执行版本检查。</p><h3 id="状态快照" tabindex="-1">状态快照 <a class="header-anchor" href="#状态快照" aria-label="Permalink to &quot;状态快照&quot;">​</a></h3><p>保存操作前状态并恢复。适合文档编辑，但快照大小、关联对象、权限和保留期需要明确。恢复一个对象不能破坏其他对象已经发生的合法变化。</p><h3 id="软删除与回收站" tabindex="-1">软删除与回收站 <a class="header-anchor" href="#软删除与回收站" aria-label="Permalink to &quot;软删除与回收站&quot;">​</a></h3><p>删除先进入可恢复状态，保留期限后再永久清除。需要定义：保留期、权限、关联数据、名称占用、外部链接与永久删除流程。</p><h3 id="补偿操作" tabindex="-1">补偿操作 <a class="header-anchor" href="#补偿操作" aria-label="Permalink to &quot;补偿操作&quot;">​</a></h3><p>跨服务或已发生外部副作用时，无法真正回到过去，只能执行补偿，例如退款而不是“撤销已结算支付”。补偿可能需要时间、费用和人工审核，界面应使用准确术语。</p><h2 id="容错" tabindex="-1">容错 <a class="header-anchor" href="#容错" aria-label="Permalink to &quot;容错&quot;">​</a></h2><p>容错不是静默猜测用户意图。可接受的处理应可预测、可检查，并避免改变关键含义。</p><h3 id="输入规范化" tabindex="-1">输入规范化 <a class="header-anchor" href="#输入规范化" aria-label="Permalink to &quot;输入规范化&quot;">​</a></h3><p>可安全处理常见空格、大小写或格式差异。例如邮箱域名或代码输入的规范化必须遵循对应规则；不要在没有业务依据时修改用户原始内容。</p><h3 id="幂等" tabindex="-1">幂等 <a class="header-anchor" href="#幂等" aria-label="Permalink to &quot;幂等&quot;">​</a></h3><p>同一业务意图重复发送不会产生额外副作用。支付、创建订单和批量导入等写操作应使用受控的幂等标识与服务端约束。禁用按钮只能减少重复点击，无法覆盖网络重试、多标签页或恶意请求。</p><h3 id="局部成功" tabindex="-1">局部成功 <a class="header-anchor" href="#局部成功" aria-label="Permalink to &quot;局部成功&quot;">​</a></h3><p>批量任务可在规则允许时保留成功项，并逐项报告失败。必须说明是否原子执行、哪些结果已生效、重试范围是什么。资金转账等事务可能要求全部成功或全部失败，不能为了容错擅自部分提交。</p><h3 id="降级" tabindex="-1">降级 <a class="header-anchor" href="#降级" aria-label="Permalink to &quot;降级&quot;">​</a></h3><p>非关键功能失败时保持主任务可用，例如头像加载失败仍显示姓名。降级不能绕过权限、安全校验或隐藏关键数据不完整。</p><h2 id="错误预防" tabindex="-1">错误预防 <a class="header-anchor" href="#错误预防" aria-label="Permalink to &quot;错误预防&quot;">​</a></h2><p>按照成本从低到高组合：</p><ol><li><strong>清晰标签和规则</strong>：让用户在输入前知道要求。</li><li><strong>合法控件与范围</strong>：日期选择器、枚举和边界限制减少无效值。</li><li><strong>即时但不过早的校验</strong>：完成输入后提示可修正问题。</li><li><strong>服务端权威校验</strong>：校验权限、最新状态和业务不变量。</li><li><strong>复核与确认</strong>：用于法律、金融、删除和不可逆结果。</li><li><strong>可逆设计</strong>：在业务允许时提供撤销、草稿、版本或回收站。</li></ol><p>确认对话框不是所有危险操作的默认方案。频繁、措辞相似的确认会被机械通过。更有效的做法包括明确对象、区分主要与危险操作、展示实际影响、允许撤销和让高风险信息在决策时可见。</p><p>WCAG 2.2 对法律承诺、金融交易、修改或删除用户可控数据等场景要求至少具备可逆、检查后可修正或最终提交前复核确认之一。它是 Web 可访问性最低要求的一部分，不等于全部产品风险控制。</p><h2 id="错误恢复" tabindex="-1">错误恢复 <a class="header-anchor" href="#错误恢复" aria-label="Permalink to &quot;错误恢复&quot;">​</a></h2><p>一个可恢复错误应包含：</p><ul><li><strong>发生了什么</strong>：使用文本描述，不只显示颜色或代码。</li><li><strong>影响什么</strong>：哪些对象已成功、失败或状态未知。</li><li><strong>为什么</strong>：在安全允许范围内给出具体原因。</li><li><strong>保留什么</strong>：用户输入、已完成步骤和上下文是否仍在。</li><li><strong>怎样继续</strong>：修正、重试、撤销、返回或联系支持。</li><li><strong>怎样验证</strong>：刷新或进入详情后从哪里查看权威结果。</li></ul><p>错误代码可以作为支持信息，但不能替代面向用户的说明。安全错误不应泄露账户、资源或内部实现细节。</p><h2 id="完整案例-批量邀请成员" tabindex="-1">完整案例：批量邀请成员 <a class="header-anchor" href="#完整案例-批量邀请成员" aria-label="Permalink to &quot;完整案例：批量邀请成员&quot;">​</a></h2><h3 id="具体输入" tabindex="-1">具体输入 <a class="header-anchor" href="#具体输入" aria-label="Permalink to &quot;具体输入&quot;">​</a></h3><p>用户向项目 P-204 邀请以下地址：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>li@example.com</span></span>
<span class="line"><span>wang@example.com</span></span>
<span class="line"><span>bad-address</span></span>
<span class="line"><span>member@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>已知状态：<code>member@example.com</code> 已是成员；用户有邀请权限；服务端对每个有效邮箱独立处理，并以“项目 ID + 规范化邮箱”作为幂等范围。</p><h3 id="处理过程" tabindex="-1">处理过程 <a class="header-anchor" href="#处理过程" aria-label="Permalink to &quot;处理过程&quot;">​</a></h3><ol><li>客户端解析每行，去除行首尾空白，但保留用户可见原始值。</li><li><code>bad-address</code> 未通过格式检查，在提交前标记并说明合法示例。</li><li>用户修正为 <code>bad@example.com</code> 后提交；客户端生成一次意图 ID。</li><li>服务端重新验证权限、项目状态、格式、现有成员和重复邀请。</li><li><code>li@example.com</code> 与 <code>bad@example.com</code> 创建邀请；<code>wang@example.com</code> 因邮件服务暂时失败进入可重试失败；<code>member@example.com</code> 返回“已是成员”，不创建邀请。</li><li>界面按结果分组，焦点移到结果标题，并允许只重试 <code>wang@example.com</code>。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>已发送：2</span></span>
<span class="line"><span>需要重试：1（wang@example.com）</span></span>
<span class="line"><span>无需邀请：1（member@example.com 已是成员）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>刷新成员页后，已发送项显示“待接受”，已有成员保持“成员”。结果不是一个笼统“部分成功”Toast，而是可重新查看的逐项状态。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>请求超时且结果未知：客户端用相同意图 ID 查询或重试，服务端不重复创建。</li><li>权限在提交前被撤销：全部拒绝，保留输入并说明申请权限路径。</li><li>项目已归档：不发送任何邀请，说明对象状态。</li><li>邮件投递稍后失败：邀请创建与投递状态分开表示，不能把“邀请已创建”写成“邮件已送达”。</li></ul><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ol><li>重复发送相同意图 ID，邀请记录数不增加。</li><li>只重试失败项，已成功项不再次发送。</li><li>仅用键盘定位错误、提交、浏览逐项结果与重试。</li><li>屏幕阅读器能获知错误数量、结果分组和状态变化。</li><li>刷新后结果与服务端成员、邀请记录一致。</li></ol><h2 id="可执行设计步骤" tabindex="-1">可执行设计步骤 <a class="header-anchor" href="#可执行设计步骤" aria-label="Permalink to &quot;可执行设计步骤&quot;">​</a></h2><ol><li>列出用户可开始、暂停、取消、退出和检查的节点。</li><li>为每个写操作定义权威不变量、事务边界和重复请求行为。</li><li>按错误成本选择约束、校验、复核与确认。</li><li>明确取消、撤销、重试、恢复和补偿的语义差异。</li><li>为错误写影响范围、输入保留、修正方式和权威验证位置。</li><li>设计键盘焦点、错误摘要、字段关联与动态状态通知。</li><li>注入慢请求、超时、断网、部分成功、权限变化和并发冲突。</li><li>从用户任务和数据不变量两侧验收。</li></ol><h2 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h2><ul><li>把关闭弹窗叫撤销，实际只是隐藏界面且数据已写入。</li><li>提供“取消”，但服务端任务仍继续且不说明。</li><li>依赖前端禁用按钮防止重复支付或创建。</li><li>自动修正高风险输入而不告知用户。</li><li>提交失败后清空合法输入或只显示顶部“有错误”。</li><li>使用确认对话框代替可逆设计和明确影响。</li><li>批量操作显示部分成功，却不列出已生效对象。</li><li>重试没有幂等保证，造成重复副作用。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>为每个动作写出开始前、进行中、成功、失败和未知结果状态。</li><li>使用重复点击、网络重放和多标签页测试幂等。</li><li>在异步处理中执行取消和离开，核对服务端实际结果。</li><li>修改对象版本或权限，验证撤销不会覆盖新数据。</li><li>仅用键盘完成错误定位、修正、重试和撤销。</li><li>用屏幕阅读器确认错误以文本描述且状态变化可感知。</li><li>刷新、重新登录和跨设备检查权威结果与恢复路径。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>设计“永久删除团队”的预防、确认、执行与恢复策略。</p><p>完成时应满足：</p><ul><li>说明哪些数据立即不可用、哪些延迟清除、哪些因法规保留；</li><li>明确权限、重新认证、对象名复核和并发检查；</li><li>区分取消、撤销、软删除、永久删除和补偿；</li><li>服务端保证授权、状态和重复请求不变量；</li><li>覆盖处理中、超时未知、部分外部清理失败和权限变化；</li><li>键盘与屏幕阅读器能理解确认和结果；</li><li>通过数据库记录、审计日志和界面结果共同验证。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C：Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/input-assistance.html" target="_blank" rel="noreferrer">W3C WAI：Understanding Guideline 3.3 Input Assistance</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/error-identification.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 3.3.1 Error Identification</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/on-focus.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 3.2.1 On Focus</a>（访问日期：2026-07-17）</li></ul>`,69)])])}const b=e(s,[["render",t]]);export{u as __pageData,b as default};
